import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Instalowanie Fabric","description":"Przewodnik krok po kroku o tym, jak zainstalować Fabric.","frontmatter":{"title":"Instalowanie Fabric","description":"Przewodnik krok po kroku o tym, jak zainstalować Fabric.","authors":["IMB11","Benonardo","modmuss50"],"files":[]},"headers":[],"relativePath":"pl_pl/1.21.4/players/installing-fabric.md","filePath":"versions/1.21.4/translated/pl_pl/players/installing-fabric.md","lastUpdated":1760721669000}`);var c={name:`pl_pl/1.21.4/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalowanie Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalowanie Fabric”">​</a></h1><p>Ten przewodnik pokaże ci, jak zainstalować Fabric dla oficjalnego launchera Minecrafta.</p><p>W przypadku innych launcherów należy zapoznać się z ich dokumentacją.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Pobierz instalator Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Pobierz instalator Fabric”">​</a></h2><p>Instalator Fabric możesz pobrać ze <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">strony Fabric</a>.</p><p>Jeśli korzystasz z systemu Windows, pobierz wersję <code>.exe</code> (<code>Download for Windows</code>), ponieważ nie wymaga ona posiadania zainstalowanej Javy. Zamiast tego wykorzystuje Javę, która jest dołączona w oficjalnym launcherze.</p><p>W przypadku systemów macOS i Linux należy pobrać wersję <code>.jar</code>. Czasami przed wykonaniem tego kroku konieczne jest zainstalowanie Javy.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Uruchom instalator Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Uruchom instalator Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Przed instalacją należy zamknąć Minecrafta, jak i jego launcher.</p></div><details class="details custom-block"><summary>Informacja dla użytkowników systemu macOS</summary><p>Na systemie macOS do uruchomienia pliku <code>.jar</code> może być konieczne kliknięcie go prawym przyciskiem myszy, a następnie wybranie opcji <code>Otwórz</code>.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Menu kontekstowe macOS z instalatorem Fabric" loading="lazy"></p><p>Gdy pojawi się komunikat „Czy na pewno chcesz otworzyć ten plik?”, ponownie kliknij <code>Otwórz</code>.</p></details><p>Po otworzeniu instalatora powinno pojawić się takie okno:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Instalator Fabric z wyróżnionym tekstem „Zainstaluj”" loading="lazy"></p><p>Aby zainstalować Fabric, wystarczy po prostu wybrać wersję gry z rozwijanej listy i kliknąć <code>Zainstaluj</code>.</p><p><strong>Upewnij się, że opcja <code>Utwórz profil</code> jest zaznaczona.</strong></p><h2 id="3-you-re-done" tabindex="-1">3. I to tyle! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. I to tyle!”">​</a></h2><p>Po zakończeniu instalacji możesz otworzyć launcher Minecrafta i wybrać z rozwijanej listy w lewym dolnym rogu profil Fabric, a następnie zacząć grać!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher Minecrafta z wybranym profilem Fabric" loading="lazy"></p><p>Teraz, po zainstalowaniu Fabric możesz dodawać mody do swojej gry! Po więcej informacji sprawdź przewodnik na temat <a href="./finding-mods">znajdowania wiarygodnych modów</a>.</p><p>Jeśli napotkasz jakiś problem podczas korzystania z tego przewodnika, możesz poprosić o pomoc na <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discordzie Fabric</a> na kanale <code>#player-support</code>.</p>`,19)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};